import { Filesystem, Directory } from '@capacitor/filesystem'
import { Capacitor } from '@capacitor/core'

// Models used by Transformers.js worker
const TRANSFORMERS_MODELS = {
  'translation': { name: 'Xenova/t5-small', size: 242 * 1024 * 1024 },
  'text-generation': { name: 'Xenova/distilgpt2', size: 261 * 1024 * 1024 },
  'summarization': { name: 'Xenova/distilbart-cnn-6-6', size: 1.2 * 1024 * 1024 * 1024 },
  'question-answering': { name: 'Xenova/distilbert-base-cased-distilled-squad', size: 248 * 1024 * 1024 },
  'zero-shot-classification': { name: 'Xenova/distilbert-base-uncased-mnli', size: 258 * 1024 * 1024 },
  'automatic-speech-recognition': { name: 'Xenova/whisper-tiny.en', size: 75 * 1024 * 1024 },
  'image-classification': { name: 'Xenova/vit-base-patch16-224', size: 330 * 1024 * 1024 }
}

export class ModelDownloader {
  constructor() {
    this.downloadProgress = {}
    this.modelsDir = 'transformers_models'
    this.isNativeAndroid = false
    this.downloadedModels = new Set()
  }

  async detectPlatform() {
    const isCapacitor = Capacitor.isNativePlatform()
    
    if (!isCapacitor) {
      console.log('💻 Running in browser - using CDN models')
      this.isNativeAndroid = false
      return false
    }
    
    try {
      const platform = Capacitor.getPlatform()
      this.isNativeAndroid = platform === 'android'
      console.log(`📱 Capacitor platform: ${platform}, isAndroid: ${this.isNativeAndroid}`)
      return this.isNativeAndroid
    } catch (error) {
      console.error('Platform detection failed:', error)
      this.isNativeAndroid = false
      return false
    }
  }

  async ensureDirectory() {
    if (!this.isNativeAndroid) return true
    
    try {
      await Filesystem.mkdir({
        path: this.modelsDir,
        directory: Directory.Data,
        recursive: true
      })
      console.log('✅ Models directory ready')
    } catch (error) {
      console.log('Directory exists or error:', error)
    }
  }

  async modelExists(modelKey) {
    if (!this.isNativeAndroid) return false
    
    try {
      await Filesystem.stat({
        path: `${this.modelsDir}/${modelKey}.status`,
        directory: Directory.Data
      })
      return true
    } catch {
      return false
    }
  }

  async markModelDownloaded(modelKey) {
    if (!this.isNativeAndroid) return
    
    try {
      await Filesystem.writeFile({
        path: `${this.modelsDir}/${modelKey}.status`,
        data: JSON.stringify({ downloaded: true, timestamp: Date.now() }),
        directory: Directory.Data
      })
      this.downloadedModels.add(modelKey)
    } catch (error) {
      console.error('Failed to mark model:', error)
    }
  }

  async getDownloadedModels() {
    if (!this.isNativeAndroid) return []
    
    const downloaded = []
    for (const modelKey of Object.keys(TRANSFORMERS_MODELS)) {
      if (await this.modelExists(modelKey)) {
        downloaded.push(modelKey)
      }
    }
    return downloaded
  }

  async downloadTransformersModel(modelKey, onProgress) {
    if (!this.isNativeAndroid) {
      console.log('💻 Skipping download - not on Android')
      return true
    }
    
    const config = TRANSFORMERS_MODELS[modelKey]
    if (!config) return false
    
    // Check if already downloaded
    const exists = await this.modelExists(modelKey)
    if (exists) {
      console.log(`✅ ${modelKey} already downloaded`)
      onProgress?.(100, config.size, config.size)
      return true
    }
    
    await this.ensureDirectory()
    
    console.log(`📥 Downloading ${modelKey} (${(config.size / 1024 / 1024).toFixed(1)} MB)...`)
    
    try {
      // Hugging Face model files
      const modelFiles = [
        `https://huggingface.co/${config.name}/resolve/main/config.json`,
        `https://huggingface.co/${config.name}/resolve/main/model.onnx`,
        `https://huggingface.co/${config.name}/resolve/main/tokenizer.json`
      ]
      
      let totalDownloaded = 0
      let totalSize = config.size
      
      for (const fileUrl of modelFiles) {
        try {
          const response = await fetch(fileUrl)
          if (!response.ok) continue
          
          const reader = response.body.getReader()
          const chunks = []
          let receivedLength = 0
          
          while (true) {
            const { done, value } = await reader.read()
            if (done) break
            
            chunks.push(value)
            receivedLength += value.length
            totalDownloaded += value.length
            
            const percent = (totalDownloaded / totalSize) * 100
            onProgress?.(percent, totalDownloaded, totalSize)
          }
          
          const blob = new Blob(chunks)
          const arrayBuffer = await blob.arrayBuffer()
          const fileName = fileUrl.split('/').pop()
          
          await Filesystem.writeFile({
            path: `${this.modelsDir}/${modelKey}_${fileName}`,
            data: Array.from(new Uint8Array(arrayBuffer)),
            directory: Directory.Data
          })
          
        } catch (err) {
          console.warn(`Failed to download ${fileUrl}:`, err)
        }
      }
      
      await this.markModelDownloaded(modelKey)
      console.log(`✅ ${modelKey} downloaded and saved`)
      return true
      
    } catch (error) {
      console.error(`Failed to download ${modelKey}:`, error)
      throw error
    }
  }

  async downloadAllModels(onProgress) {
    if (!this.isNativeAndroid) {
      console.log('💻 Browser/PC detected - using CDN models')
      return true
    }
    
    console.log('🤖 Starting Transformers.js model downloads for Android...')
    const models = Object.keys(TRANSFORMERS_MODELS)
    let completed = 0
    
    for (const modelKey of models) {
      try {
        await this.downloadTransformersModel(modelKey, (percent, loaded, total) => {
          onProgress?.(modelKey, percent, loaded, total, completed, models.length)
        })
        completed++
        onProgress?.(modelKey, 100, TRANSFORMERS_MODELS[modelKey].size, TRANSFORMERS_MODELS[modelKey].size, completed, models.length)
      } catch (error) {
        console.error(`Failed to download ${modelKey}:`, error)
        // Continue with other models
      }
    }
    
    return true
  }

  async getModelStatus() {
    const status = {}
    for (const [modelKey, config] of Object.entries(TRANSFORMERS_MODELS)) {
      status[modelKey] = {
        name: modelKey,
        modelName: config.name,
        downloaded: await this.modelExists(modelKey),
        size: config.size
      }
    }
    return status
  }
}

export const modelDownloader = new ModelDownloader()